import hashlib
import secrets
from typing import List, Tuple

class FORS:
    def __init__(self, k: int, a: int, n: int = 32):
        self.k = k
        self.a = a
        self.n = n
        self.leaves_per_tree = 2 ** a

    def _hash(self, data: bytes) -> bytes:
        return hashlib.sha256(data).digest()[:self.n]

    def _prf(self, key: bytes, addr: bytes) -> bytes:
        return hashlib.sha256(key + addr).digest()[:self.n]

    def _build_tree(self, sk_seed: bytes, tree_idx: int) -> Tuple[List[bytes], bytes]:
        leaves = []
        for i in range(self.leaves_per_tree):
            addr = tree_idx.to_bytes(4, 'big') + i.to_bytes(4, 'big')
            secret = self._prf(sk_seed, addr)
            leaves.append(self._hash(secret))

        level = leaves
        for _ in range(self.a):
            next_level = []
            for j in range(0, len(level), 2):
                next_level.append(self._hash(level[j] + level[j+1]))
            level = next_level
        return leaves, level[0]

    def keygen(self, seed: bytes = None) -> Tuple[bytes, bytes]:
        if seed is None:
            seed = secrets.token_bytes(self.n)
        roots = [self._build_tree(seed, i)[1] for i in range(self.k)]
        pk = self._hash(b''.join(roots))
        return seed, pk

    def message_indices(self, msg_hash: bytes) -> List[int]:
        bits = ''.join(format(b, '08b') for b in msg_hash)
        indices = []
        for i in range(self.k):
            chunk = bits[i*self.a:(i+1)*self.a]
            indices.append(int(chunk, 2) if len(chunk) == self.a else 0)
        return indices

    def _auth_path(self, leaves: List[bytes], idx: int) -> List[bytes]:
        path = []
        level = leaves
        for _ in range(self.a):
            path.append(level[idx ^ 1])
            next_level = []
            for j in range(0, len(level), 2):
                next_level.append(self._hash(level[j] + level[j+1]))
            level = next_level
            idx //= 2
        return path

    def sign(self, sk_seed: bytes, message: bytes) -> dict:
        msg_hash = self._hash(message)
        indices = self.message_indices(msg_hash)
        sig = {'leaves': [], 'auth_paths': []}

        for tree_idx in range(self.k):
            leaves, _ = self._build_tree(sk_seed, tree_idx)
            leaf_idx = indices[tree_idx]
            addr = tree_idx.to_bytes(4, 'big') + leaf_idx.to_bytes(4, 'big')
            sig['leaves'].append(self._prf(sk_seed, addr))
            sig['auth_paths'].append(self._auth_path(leaves, leaf_idx))
        return sig

    def verify(self, pk: bytes, message: bytes, sig: dict) -> bool:
        msg_hash = self._hash(message)
        indices = self.message_indices(msg_hash)
        roots = []

        for tree_idx in range(self.k):
            current = self._hash(sig['leaves'][tree_idx])
            idx = indices[tree_idx]
            for sibling in sig['auth_paths'][tree_idx]:
                if idx % 2 == 0:
                    current = self._hash(current + sibling)
                else:
                    current = self._hash(sibling + current)
                idx //= 2
            roots.append(current)

        return self._hash(b''.join(roots)) == pk

from typing import List, Tuple

class HypertreeNavigator:
    def __init__(self, h: int, d: int):
        self.h = h
        self.d = d
        self.hp = h // d

    def leaf_to_path(self, leaf_idx: int) -> List[Tuple[int, int]]:
        path = []
        idx = leaf_idx
        leaves_per_tree = 2 ** self.hp

        for layer in range(self.d):
            leaf_in_tree = idx % leaves_per_tree
            tree_idx = idx // leaves_per_tree
            path.append((tree_idx, leaf_in_tree))
            idx = tree_idx

        return path

    def trees_at_layer(self, layer: int) -> int:
        return 2 ** (layer * self.hp)

    def total_virtual_leaves(self) -> int:
        return 2 ** self.h

    def signature_components(self) -> dict:
        return {
            'wots_signatures': self.d,
            'auth_paths': self.d,
            'nodes_per_path': self.hp,
            'total_auth_nodes': self.d * self.hp
        }

