from typing import Dict

class HashSigComparison:
    SCHEMES = {
        'XMSS-SHA2_10_256': {'sig_kb': 2.5, 'stateful': True, 'max_sigs': 2**10},
        'XMSS-SHA2_20_256': {'sig_kb': 2.8, 'stateful': True, 'max_sigs': 2**20},
        'LMS-SHA256_M32_H10': {'sig_kb': 1.6, 'stateful': True, 'max_sigs': 2**10},
        'SLH-DSA-SHA2-128s': {'sig_kb': 7.9, 'stateful': False, 'max_sigs': float('inf')},
        'SLH-DSA-SHA2-128f': {'sig_kb': 17.1, 'stateful': False, 'max_sigs': float('inf')}
    }

    def recommend(self, use_case: str) -> str:
        use_case = use_case.lower()
        if 'hsm' in use_case or 'firmware' in use_case:
            return 'XMSS-SHA2_20_256 (stateful, small sigs, HSM manages state)'
        elif 'web' in use_case or 'tls' in use_case:
            return 'SLH-DSA-SHA2-128f (stateless, fast, larger sigs ok)'
        elif 'email' in use_case or 'document' in use_case:
            return 'SLH-DSA-SHA2-128s (stateless, smaller sigs, speed less critical)'
        else:
            return 'SLH-DSA-SHA2-128s (safe default, stateless)'

    def size_comparison(self) -> Dict:
        return {name: props['sig_kb'] for name, props in self.SCHEMES.items()}
